import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Validate user input to prevent XSS attacks
        if(userInput != null && !userInput.isEmpty()) {
            // Encode user input before including it in the response
            String encodedUserInput = encodeHTML(userInput);
            response.getWriter().println("<p>User Input: " + encodedUserInput + "</p>");
        } else {
            response.getWriter().println("<p>No user input provided</p>");
        }
    }

    private String encodeHTML(String input) {
        // Replace special characters with their HTML entities to prevent XSS
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
